import React from 'react'
import { Line } from 'react-chartjs-2'

function Corona(jsonArray) {

  let prevMonth = 0
  let curMonth = 0
  let chartDataArray = []
  let chartLabelArray = []
  let start, finish
  let today
  
  const sorting = () => {
    console.time('sorting')
    jsonArray.props.map((data) => {
      let confirmed;
      curMonth = parseInt(data.Date.substring(5,7), 10) // 2,4 년 5,7 월 8,10 일
      if((curMonth - prevMonth) !== 0) {
        chartDataArray.push(data.Confirmed)
        chartLabelArray.push(data.Date.substring(2,7))
        prevMonth = curMonth
      }
      else {
        chartDataArray.splice(-1)
        chartDataArray.push(data.Confirmed)
      }
      today = data.Date.substring(2,10)
      return confirmed
    })
    console.timeEnd('sorting')
    // console.log("chartDataArray", chartDataArray, "\n", "chartLabelArray" , chartLabelArray)
  }

  sorting()
  
  return (
    <div className='Corona'>
      <Line 
        data={{
          labels: chartLabelArray,
          datasets: [{
            label: '월별 코로나 확진자 현황 ' + today + ' 기준',
            data: chartDataArray,
            borderColor: 'rgb(75, 192, 192)',
            tension: 0.3
          }]
        }}
        options={{
          scales: {
            x: {
              display: true
            },
            y: {
              beginAtZero: true,
              max: 220000
            }
          }
        }}
        className='line-chart'
      />
    </div>
  )
}

export default Corona;
