import React from 'react'
import { Line } from 'react-chartjs-2'

function Corona(jsonArray) {

  const chartData = jsonArray.props.map(data => data.Confirmed)
  const chartLabel = jsonArray.props.map(data => data.Date.substring(2,10))

  return (
    <div className="Corona">
      { /* console.log("chartData", chartData, "chartLabel", chartLabel) */ }
      <Line 
        data={{
          labels: chartLabel,
          datasets: [{
            label: "코로나 확진자 현황",
            data: chartData,
            borderColor: 'rgb(75, 192, 192)',
            tension: 0.3
          }]
        }}
        options={{
          scales: {
            x: {
              display: true
            },
            y: {
              beginAtZero: true,
              max: 220000
            }
          }
        }}
        className="line-chart"
      />
    </div>
  )
}

export default Corona;
